/**
 * Deduplicate and sort array of strings case-insensitively.
 * @param {Array<string>} arr
 * @returns {Array<string>}
 */
function dedupeAndSortCaseInsensitive(arr) {
  const lowered = new Set();
  const result = [];
  for (const item of arr) {
    const lower = item.toLowerCase();
    if (!lowered.has(lower)) {
      lowered.add(lower);
      result.push(item);
    }
  }
  result.sort(caseInsensitiveCompare);
  return result;
}

